c.push(CODE([
  'private DepthMap AnalyzeDepth(Image<Rgba32> image) {',
  '    var depth = new DepthMap { Width = image.Width, Height = image.Height,',
  '        Values = new float[image.Height, image.Width] };',
  '    float min = 1f, max = 0f;',
  '    for (int y = 0; y < image.Height; y++)',
  '      for (int x = 0; x < image.Width; x++) {',
  '        var p = image[x, y];',
  '        // перцептивная яркость (eye-weighted)',
  '        float lum = (0.299f*p.R + 0.587f*p.G + 0.114f*p.B) / 255f;',
  '        depth.Values[y, x] = lum;',
  '        if (lum < min) min = lum; if (lum > max) max = lum;',
  '      }',
  '    float range = MathF.Max(1e-4f, max - min);   // растяжение контраста по кадру',
  '    for (int y = 0; y < image.Height; y++)',
  '      for (int x = 0; x < image.Width; x++)',
  '        depth.Values[y, x] = (depth.Values[y, x] - min) / range;',
  '    ApplyGaussianBlur(depth.Values);',
  '    return depth;',
  '}',
]));

